import javax.naming.Context;
import javax.naming.NamingEnumeration;
import javax.naming.NamingException;
import javax.naming.directory.Attribute;
import javax.naming.directory.Attributes;
import javax.naming.directory.DirContext;
import javax.naming.directory.InitialDirContext;
import javax.naming.directory.SearchControls;
import javax.naming.directory.SearchResult;
import javax.naming.ldap.LdapName;
import java.util.Hashtable;
import java.util.HashMap;
import java.util.Map;

public class LdapUserSearch {

    public Map<String, String> findUserByUsername(
            String username,
            String ldapUrl,
            String baseDn,
            String usernameAttribute,
            String bindDn,
            String bindPassword) {

        Map<String, String> userAttributes = new HashMap<>();
        DirContext ctx = null;

        try {
            Hashtable<String, String> env = new Hashtable<>();
            env.put(Context.INITIAL_CONTEXT_FACTORY, "com.sun.jndi.ldap.LdapCtxFactory");
            env.put(Context.PROVIDER_URL, ldapUrl);
            env.put(Context.REFERRAL, "follow"); // Follow referrals if the server sends them

            if (bindDn != null && !bindDn.isEmpty()) {
                env.put(Context.SECURITY_AUTHENTICATION, "simple");
                env.put(Context.SECURITY_PRINCIPAL, bindDn);
                env.put(Context.SECURITY_CREDENTIALS, bindPassword);
            } else {
                env.put(Context.SECURITY_AUTHENTICATION, "none"); // Anonymous bind
            }

            ctx = new InitialDirContext(env);

            SearchControls searchControls = new SearchControls();
            searchControls.setSearchScope(SearchControls.SUBTREE_SCOPE); // Search entire subtree

            // Attributes to retrieve from the LDAP entry
            // "mail" for email, "cn" (Common Name) for full name, "displayName" (AD specific) for full name,
            // "givenName" (first name), "sn" (surname) for constructing full name, and "department".
            // The usernameAttribute is also included in case it's useful for debugging or additional checks.
            String[] returningAttributes = {"mail", "cn", "displayName", "givenName", "sn", "department", usernameAttribute};
            searchControls.setReturningAttributes(returningAttributes);

            // Construct the search filter: search for objects with objectClass=person and the specified username attribute
            String escapedUsername = LdapName.escape(username); // Sanitize username for LDAP filter
            String searchFilter = String.format("(&(objectClass=person)(%s=%s))", usernameAttribute, escapedUsername);

            NamingEnumeration<SearchResult> results = ctx.search(baseDn, searchFilter, searchControls);

            if (results.hasMore()) {
                SearchResult sr = results.next();
                Attributes attrs = sr.getAttributes();

                // Retrieve and map attributes to the desired keys
                Attribute emailAttr = attrs.get("mail");
                if (emailAttr != null && emailAttr.get() != null) {
                    userAttributes.put("email", (String) emailAttr.get());
                }

                // Attempt to get "fullName" in a prioritized order: cn -> displayName -> (givenName + sn)
                Attribute cnAttr = attrs.get("cn");
                Attribute displayNameAttr = attrs.get("displayName");
                Attribute givenNameAttr = attrs.get("givenName");
                Attribute snAttr = attrs.get("sn");

                if (cnAttr != null && cnAttr.get() != null) {
                    userAttributes.put("fullName", (String) cnAttr.get());
                } else if (displayNameAttr != null && displayNameAttr.get() != null) {
                    userAttributes.put("fullName", (String) displayNameAttr.get());
                } else {
                    String givenName = (givenNameAttr != null && givenNameAttr.get() != null) ? (String) givenNameAttr.get() : "";
                    String sn = (snAttr != null && snAttr.get() != null) ? (String) snAttr.get() : "";
                    String combinedName = (givenName + " " + sn).trim();
                    if (!combinedName.isEmpty()) {
                        userAttributes.put("fullName", combinedName);
                    }
                }

                Attribute deptAttr = attrs.get("department");
                if (deptAttr != null && deptAttr.get() != null) {
                    userAttributes.put("department", (String) deptAttr.get());
                }
            }
        } catch (NamingException e) {
            // Log the exception for debugging. In a production system, you might use a logger
            // and throw a more specific exception or return a clearly defined error state.
            System.err.println("LDAP search failed: " + e.getMessage());
            // e.printStackTrace(); // Uncomment for detailed stack trace
            return new HashMap<>(); // Return empty map on error or user not found
        } finally {
            if (ctx != null) {
                try {
                    ctx.close(); // Ensure the context is closed
                } catch (NamingException e) {
                    System.err.println("Error closing LDAP context: " + e.getMessage());
                    // e.printStackTrace();
                }
            }
        }
        return userAttributes;
    }
}